function LxGuideCtrl:CheckGuideTip()
    self:StopGuideTip();
    local isShow = CtrlCenter.FuncOpen:IsFuncShow(FuncIds.Task)
    if(not isShow)then
        return
    end
    if(ModuleCenter.Story:IsNewbieRunning())then
        return
    end
    if(self:IsGuideRun())then
        return
    end
    local curScene = MgrCenter.LevelMgr:GetCurrentLevelName()
    if(curScene == "Main")then
        local curMain = MgrCenter.PanelMgr:IsCurMain()
        if(curMain == false)then
            return
        end
        self:CheckTaskTips()
        self:CheckExploreTips()
    elseif curScene == "World" then
        local curMain = MgrCenter.PanelMgr:IsCurWorldMain();
        if(curMain == false)then
            return
        end
        self:CheckWorldExplore()
    end

end
