function LxGuideCtrl:TryStartWaitTrigger()
    if not self:IsEnterCity() then return end
    if self:IsGuideRun() then return end
    local triggerData = ModuleCenter.Guide.waitTriggerData
    if triggerData then
        ModuleCenter.Guide.waitTriggerData = nil
        local guidId = self:GetTriggerGuideId(triggerData)
        if guidId > 0 then
            self:StartGuide(guidId)
            return true
        end
    end
end

