    local typeDict = string.split(config.guideId,"|")
    for i, v in pairs(typeDict) do
        local typeData = string.split(v,"=")
        if(checknumber(typeData[1]) == 0)then
            return checknumber(typeData[2])
        end
        if(checknumber(typeData[1]) == curLevelType)then
            return checknumber(typeData[2])
        end
    end
