function LxGuideCtrl:RealStartGuide(refId)
    --对繁荣度升级特殊处理
    --ClosePanel(UiNames.PeopleHeartUp)

    ModuleCenter.Guide:SetRunningGuide(refId)

    FireEvent(EventNames.GUIDE_TK_STEP_START, refId)

    local ref = GameTable.NewPlayerGuideEventRef[refId]
    if not ref then
        if LOG_INFO_ENABLED then
            printError("指引", "不存在指引配置 refId =%s", tostring(refId))
            self:FinishGuide()
            return
        end
    end

    if LOG_INFO_ENABLED then
        printInfo("指引", "<color=#00ff00>当前执行的指引refId=%s</color>", tostring(refId))
    end
    FireEvent(EventNames.GUIDE_START)

    ShowPanel(UiNames.Guide, {refId = refId})
end

