---结束引导
function LxGuideCtrl:FinishGuide()
    local guideModule = ModuleCenter.Guide
    local curId = guideModule:GetRunningGuide()
    if curId <= 0 then return end

    guideModule:SetRunningGuide(0)

    local triggerData = guideModule:GetTriggerDataByGuideId(curId)
    --local triggerKey = triggerData.refId
    local triggerKey = guideModule:GetCurGuideConditionRefId()
    local skipList = self:GetSkipGuides(curId)
    table.insert(skipList, -1)

    HandlerCenter.Role:GuideChangeReq(triggerKey, skipList)


    local uiGuideCtrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.Guide)
    if uiGuideCtrl then
        uiGuideCtrl:OnFinishedGuide(curId)
    end

    if self._finishedGuideCb then
        local cb = self._finishedGuideCb
        self._finishedGuideCb = nil
        cb()
    end
    guideModule:SetCurGuideConditionRefId(0)
    if(triggerKey ~= 0)then
        local t1,t2 = CtrlCenter.Story:CheckTrigger(NewbieTriggerType.GuideEnd,triggerKey)
        if (t1 > 0 and t2 > 0) then
            CtrlCenter.Story:StartStory(t2);
            return
        end
    end
    --self:DoTrigger(_triggerEnums.GuideFinished, 0)
    self:DoTrigger()
    FireEvent(EventNames.GUIDE_FINISH, curId)
end

