function LxGuideCtrl:NextGuide(guideId)
    local curId = ModuleCenter.Guide:GetRunningGuide()
    if curId ~= guideId then
        if LOG_INFO_ENABLED then
            printError("Guide", "请求下一个指引的非当前指引 curId=%s, reqId =%s", tostring(curId), tostring(guideId))
        end
        return
    end
    --local triggerData = ModuleCenter.Guide:GetTriggerDataByGuideId(guideId)
    local triggerKey = ModuleCenter.Guide:GetCurGuideConditionRefId()
    HandlerCenter.Role:GuideChangeReq(triggerKey,{guideId})
    local nextId = self:GetNextGuideId(curId)
    if nextId == 0 then
        self:FinishGuide()
        return
    end

    self:RealStartGuide(nextId)
end

function LxGuideCtrl:GetNextGuideId()
    local curId = ModuleCenter.Guide:GetRunningGuide()
    local ref = GameTable.NewPlayerGuideEventRef[curId]
    if ref then
        return ref.next
    end
    return 0
end

