function LxGuideCtrl:IsSomeGuideRun()
    local runGuide = ModuleCenter.Guide:GetRunningGuide()
    if(runGuide and runGuide > 0)then
        local config = GameTable.NewPlayerGuideEventRef[runGuide]
        if(config.type ~= 3)then
            return true
        end
