function LxGuideCtrl:HasGuideOrWaitGuide()
    if self:IsGuideRun() then
        local runGuide = ModuleCenter.Guide:GetRunningGuide()
        if(runGuide > 0)then
            local config = GameTable.NewPlayerGuideEventRef[runGuide]
            if(config.type == 3)then
                return false
            end
        end
        return true
    end

    local waitId = ModuleCenter.Guide.waitGuide
    if waitId and waitId > 0 then
        return true
    end
    if ModuleCenter.Guide.waitTriggerData then
        return true
    end
    return false
end

