function LxGuideCtrl:InitGuideDatas()
    self._isInitOk = true
    local guideModule = ModuleCenter.Guide

    local conditionMap = guideModule:GetTriggerConditionMap()
    local progress = guideModule:GetProgress()
    local finishedGuideIds = guideModule:GetFinishedGuideIds()

    local triggerConditionList = {}
    local triggeredIds = {}

    for k,v in pairs(finishedGuideIds) do
        --triggeredIds[v] = true
    end

    local triggerData = guideModule:GetTriggerDataByGuideId(progress)
    if triggerData then
        triggeredIds[triggerData.refId] = nil
    end

    for k,v in pairs(conditionMap) do
        if not triggeredIds[k] then
            table.insert(triggerConditionList, v)
        end
    end

    local ref = GameTable.NewPlayerGuideEventRef[progress]
    local againId = ref and ref.again or 0
    guideModule:SetWaitGuide(againId)
    guideModule:SetTriggerConditionList(triggerConditionList)
    guideModule:SetTriggeredIdList(triggeredIds)
end


function LxGuideCtrl:InitGuideConfig()
    local cdtMap = {}
    local guidToTriggerMap = {}
    local tempConfigDatas = {}
    for i, v in pairs(GameTable.NewPlayerGuideConditionRef) do
        table.insert(tempConfigDatas,v)
    end
    table.sort(tempConfigDatas, function(a,b)
        return a.sort < b.sort
    end)
    for k,v in ipairs(tempConfigDatas) do
        local refId = v.refId
        local guideId = v.guideId
        local preConditions = self:ParseCondition(v.fristCondition)
        local condition = self:ParseCondition(v.condition)

        local guideList = self:ParseGuideList(guideId)
        self:GenGuidToTriggerMap(guideList, guidToTriggerMap, refId)
        local t = {
            refId = refId,
            guideList = guideList,
            preCdtList = preConditions,
            triggerCdt = condition,
        }
        cdtMap[refId] = t
    end
    ModuleCenter.Guide:SetTriggerConditionMap(cdtMap)
    ModuleCenter.Guide:SetGuideToTriggerMap(guidToTriggerMap)
end

function LxGuideCtrl:GenGuidToTriggerMap(guideList, guidMaps, triggerId)
    for k,guideId in pairs(guideList) do
        local ref = GameTable.NewPlayerGuideEventRef[checknumber(guideId)]
        local map = {}
        while ref ~= nil do
            local refId = ref.refId
            if guidMaps[refId] then
                break
            end
            if  map[refId] then
                if LOG_INFO_ENABLED then
                    printError("guide", "指引表下一个指引填写的数据有死循环 refId = "..tostring(refId))
                end
                break
            end
            map[refId] = true
            if guidMaps then
                guidMaps[refId] = triggerId
            end
            ref = GameTable.NewPlayerGuideEventRef[ref.next]
        end
    end
end

function LxGuideCtrl:ParseConditionList(strList)
    if string.isempty(strList) then
        return {}
    end
    local dataList = {}
    for k,v in ipairs(strList) do
        table.insert(dataList,self:ParseCondition(v))
    end
    return dataList
end

function LxGuideCtrl:ParseCondition(str)
    local arr = string.split(str,",")
    local length = table.nums(arr)
    local res = {}
    for i = 1, length do
        local oneData = string.split(arr[i],"=")
        local type = oneData[1]
        local par = {}
        local parLength = table.nums(oneData)
        for j = 2, parLength do
            table.insert(par,oneData[j])
        end
        local data = {
            type = type,
            para = par
        }
        table.insert(res,data)
    end
    return res;
end

function LxGuideCtrl:ParseGuideList(strList)
    if(string.isempty(strList))then
        return {}
    end

    local res = {}
    local arr = string.split(strList,"|")
    local count = table.nums(arr)
    for i = 1, count do
        local data = string.split(arr[i],"=")
        local type = checknumber(data[1])
        local id = checknumber(data[2])
        res[type] = id
    end
    return res;

end

---@region trigger
function LxGuideCtrl:OnEnterCity()
    if LOG_INFO_ENABLED then
        printInfo("指引", "<color=#ffff00>进入主城，检测指引触发</color>")
    end
    ModuleCenter.Guide.enterCity = true
    --self:DoTrigger(_triggerEnums.FirstEnterGame, 1)
    self:DoTrigger()
    --判断有没有之前没有做完的引导
    if(self:IsGuideRun())then
        return
    end
    local lastGuideId = ModuleCenter.Guide:GetProgress()
    local lastGuideCfg = GameTable.NewPlayerGuideEventRef[lastGuideId]
    if(lastGuideCfg == nil or lastGuideCfg.next == nil or lastGuideCfg.next == 0)then
        --下一步是空的，也是证明结束
        return
    end
    local curGuideId = lastGuideCfg.again;

    local triggerData = ModuleCenter.Guide:GetTriggerDataByGuideId(curGuideId)
    if(triggerData == nil)then
        return
    end
    ModuleCenter.Guide:SetCurGuideConditionRefId(triggerData.refId)
    self:StartGuide(curGuideId)
    --self:DoTrigger(_triggerEnums.GuideFinished, 0)
end

function LxGuideCtrl:OnCheckStartWait()
    self:TryStartWaitTrigger()
end

function LxGuideCtrl:OnPanelCreated(uiKey, uiName)
    --self:DoTrigger(_triggerEnums.PrefabName,uiKey)
    self:DoTrigger(_triggerEnums.PrefabName,uiKey)
    local include = {
        [UiNames.MainCenter] = true,
        [UiNames.MainActivity] = true,
        [UiNames.MainRole] = true,
        [UiNames.MainBottom] = true,
        [UiNames.GmFloat] = true,
        [UiNames.SysMask] = true,
        [UiNames.Notch] = true,
        [UiNames.SysMsg] = true,
        [UiNames.PeopleNoticePop] = true,
        [UiNames.NetBlock] = true,
        [UiNames.FloatUpInfo] = true,
        [UiNames.MainNotice] = true,
        [UiNames.Guide] = true,
    }
    local curMain = MgrCenter.PanelMgr:IsCurMain()
    if(curMain == false)then
        self:StopGuideTipCheckTimer()
        local cur = ModuleCenter.Guide:GetRunningGuide()
        local config = GameTable.NewPlayerGuideEventRef[cur]
        if(config == nil) then
            return
        end
        local ui = nil
        local uiTargetChildPath = nil
        if not string.isempty(config.path) then
            local s,e = string.find(config.path, "/")
            if s and e then
                ui = string.sub(config.path, 1, s - 1)
                uiTargetChildPath = string.sub(config.path, e + 1)
            end
        end
        for i, v in pairs(include) do
            if(i == uiKey)then
                return
            end
        end
        if(uiKey == ui )then
            return
        end
        self:StopGuideTip();
    end

end

function LxGuideCtrl:OnPanelClosed(uiKey, uiName)
    self:CheckGuideTip()
end

function LxGuideCtrl:OnInstanceEventFinished()
    --self:DoTrigger(_triggerEnums.InsFinished)
    self:DoTrigger()
end

