---检测前置条件
function LxGuideCtrl:CheckPreConditions(cdtList,checkType,param)
    for k,v in ipairs(cdtList) do
        local tType = v.type
        local para = v.para
        if not self:CheckCondition(tType, para,checkType,param) then
            return false
        end
    end
    return true
end

---检测条件
function LxGuideCtrl:CheckCondition(tType, tPara,checkType,param)
    tType = checknumber(tType)
    if(tType == _triggerEnums.MapStronghold)then
        --推图
        local completeMissionId = ModuleCenter.FightIdle:GetCompleteMission()
        if(completeMissionId >= checknumber(tPara[1]))then
            return true
        end
        return false
    elseif tType == _triggerEnums.StoryTriggerEnd then
        if(checknumber(tPara[1]) == param)then
            return CtrlCenter.Story:StoryTriggerIsEnd(checknumber(tPara[1]))
        end
    elseif tType == _triggerEnums.BuildLevelUping then
        if(checknumber(tPara[1]) == param)then
            return true;
        end
        return false
    elseif tType == _triggerEnums.TaskJump then
        --任务跳转
        if(checknumber(tPara[1]) == param)then
            return true
        end
        return false
    elseif tType == _triggerEnums.FirstEnterGame then
        --首次进入游戏
        return CtrlCenter.Role:IsFirstLogin()
    elseif tType == _triggerEnums.PlotRefId then
        --剧情refId（填最后一个剧情ID）
        if(checknumber(tPara[1]) == param)then
            return CtrlCenter.Story:IsPassPlot(checknumber(tPara[1]))
        end


    elseif tType == _triggerEnums.ReName then
        --新手改名成功后触发
        return CtrlCenter.Role:IsFirstReName()
    elseif tType == _triggerEnums.RoleLevel then
        --人物等级，人物升级到X级后触发
        local building = ModuleCenter.Building:GetBuildingInfo(1001)
        if(building == nil)then
            return false
        end
        if(building.level >= checknumber(tPara[1]))then
            return true
        end
        return false
    elseif tType == _triggerEnums.CityMonsterFormation then
        if(checknumber(tPara[1]) == param)then
            return true
        end
        return false
    elseif tType == _triggerEnums.ConditionNotTrigger then
        --条件表的refId没触发，用于互斥
        return self:IsNotPassCondition(checknumber(tPara[1]))
    elseif tType == _triggerEnums.NotFirstRecharge then
        --还没进行首冲
    elseif tType == _triggerEnums.GuildBattle_GuildPanel then
        --联盟混战指引，报名期间，在联盟大厅
    elseif tType == _triggerEnums.GuildBattle_SignUpPanel then
        --联盟混战指引，报名期间，在报名界面
    elseif tType ==  _triggerEnums.ResonanceCrystal then
        --21=1,共鸣魔镜达到255级
    elseif tType == _triggerEnums.PrefabName then
        --预制体名字=cell参数=小页签参数，首次进入某个界面触发
        local panelIsOpen = self:PanelIsOpen(tPara[1])
        if(panelIsOpen == false)then
            return false
        end
        --判断小页签
        --0.0
        return true
    elseif tType == _triggerEnums.ServerDays then
        --开服天数
        local day = CtrlCenter.Role:GetServerDays()
        if(day >= checknumber(tPara[1]))then
            return true
        end
        return false
    elseif tType == _triggerEnums.NotPassMainCopy then
        --未通关某个主线关卡
    elseif tType == _triggerEnums.InRankWin then
        --玩家在开启期间进入神裔爵位赛界面（用于互斥条件）
    elseif tType == _triggerEnums.PassGuideEvent then
        --新手事件表剧情开始id，结束某段剧情事件后触发
        return CtrlCenter.Story:StoryTriggerIsEnd(tPara[1])
    elseif tType == _triggerEnums.BattleLose then
        --战斗失败触发指引
    end
    return false
end
function LxGuideCtrl:PanelIsOpen(panelName)
    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(panelName)
    if(ctrl == nil)then
        --return false
        ctrl = MgrCenter.PanelMgr:GetChildPanelCtrl(panelName)
    end
    if(ctrl == nil)then
        return false
    end
    return ctrl:IsShow()
end
function LxGuideCtrl:GetTriggerGuideId(triggerData)

    local guideList = triggerData.guideList
    if not guideList then
        return 0
    end
    local all = guideList[0]
    if all then
        return all
    end
    local guide = 0
    local levelType = self:GetLevelType()
    if levelType then
        guide = guideList[levelType] or 0
    end
    return guide
end

function LxGuideCtrl:GetLevelType()
    if MgrCenter.LevelMgr:IsInLevel(LevelNames.Main) then
        --主城
        return 6
    elseif MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle) then
        --英雄
        return 2
    elseif MgrCenter.LevelMgr:IsInLevel(LevelNames.DreamTrip) then
        --背包
        return 3
    elseif MgrCenter.LevelMgr:IsInLevel(LevelNames.World) then
        --地图
        return 5
    elseif MgrCenter.LevelMgr:IsInLevel(LevelNames.FightIdle) then
        --征战
        return 1
    elseif MgrCenter.LevelMgr:IsInLevel(LevelNames.Guild) then
        --公会
        return 4
    end
end

---引导触发，关键函数，引导到触发由此开启
function LxGuideCtrl:DoTrigger(triggerType , para)
    --do return end
    if self:IsSomeGuideRun() then
        return
    end

    local triggerData = self:GetReadyTrigger(triggerType, para)
    if not triggerData then
        return
    end
    --local runNewbie = ModuleCenter.Story:IsNewbieRunning()
    --if(runNewbie)then
    --    return
    --end
    local guideId = self:GetTriggerGuideId(triggerData)

    if guideId == 0 then
        return
    end
    local pass = self:IsPassCondition(triggerData.refId)
    if(pass)then
        --已经做过了
        return
    end
    if not self:IsEnterCity() then
        ModuleCenter.Guide.waitTriggerData = triggerData
        return
    end
    ModuleCenter.Guide:SetCurGuideConditionRefId(triggerData.refId)
    self:StartGuide(guideId)
end

---获取满足条件到触发数据
function LxGuideCtrl:GetReadyTrigger(checkType, param)
    if not self._isInitOk then
        return
    end
    local readyTriggers = {}
    local triggers = ModuleCenter.Guide:GetTriggerConditionList()
    for k,v in ipairs(triggers) do
        local preCdtList = v.preCdtList
        local isPreReady = self:CheckPreConditions(preCdtList,checkType,param)
        local isOk = false
        if isPreReady then
            isOk = self:CheckPreConditions(v.triggerCdt,checkType,param)

        end
        if isOk then
            --判断有没有做过
            local pass = self:IsPassCondition(v.refId)
            if(pass == false)then
                table.insert(readyTriggers, v)
            end

        end
    end
    if #readyTriggers == 0 then
        return
    end
    if(#readyTriggers > 1)then
        --table.sort(readyTriggers, function(a, b) return a.sort < b.sort  end)
    end

    return readyTriggers[1]
end


function LxGuideCtrl:GetSkipGuides(curId)
    local retList = {}
    local nextId = curId
    local duplicateMap = {}
    while true do
        local ref = GameTable.NewPlayerGuideEventRef[nextId]
        if not ref then
            break
        end
        if duplicateMap[nextId] then
            break
        end
        duplicateMap[nextId] = true
        table.insert(retList, nextId)
        nextId = ref.next
    end
    return retList
end
--条件表的refId没触发,用于互斥
function LxGuideCtrl:IsNotPassCondition(refId)
    local passList = ModuleCenter.Guide:GetFinishedGuideIds()
    for i, v in pairs(passList) do
        if(v == refId)then
            return false
        end
    end
    return true
end
function LxGuideCtrl:IsPassCondition(id)
    local passList = ModuleCenter.Guide:GetFinishedGuideIds()
    for i, v in ipairs(passList) do
        if(v == id)then
            return true
        end
    end
    return false
end

return LxGuideCtrl